const i={gallery:"Відеогалерея",manufacturing:"Виробництво",documentation:"Нормативна документація",contacts:"Контакти"},a={privacy:"© 2026 UPP Systems. Усі права захищено.",accordionTitle:"Навігація"},l={title:"<strong>ТОВ УКРТРУБОШПУНТ</strong>",subtitle:'<strong> перша компанія в Україні, </strong> що <u>ексклюзивно</u> виробляє трубошпунтові та балочно-шпунтові палі на основі патентованої технології MF-Pipe, розробленої компаніями SteelWall ISH GmbH (Німеччина). <br/> Трубошпунтові та балочно-шпунтові палі вже багато років широко застосовуються у світі майже на всіх інфраструктурних та гідротехнічних проєктах. <br/> <br/> <span class="hero__lg">Тепер ми їх виробляємо в Україні.</span><br/> <br/> У виробництві використовуються <br/> <strong><u> сертифіковані сталеві труби </u></strong> та двотаврові балки різних виробників <br/> + <br/> <strong><u> унікальні патентовані шпунтові замки </strong></u> SteelWall ISH GMBH, що постачаються в Україну ексклюзивно STEELWALL UKRAINE (www.steelwallukr.com ymatt24@yahoo.com) <br/> <br/> Це дозволяє створювати <span class="hero__lg">високонадійні трубошпунтові </span>системи для складних об’єктів цивільного та гідротехнічного будівництва, таких як:<br/><br/> • портова інфраструктура (моли, причали, берегоукріплення)<br/> • підпірні стінки (віадуки, дорожні розв’язки різних рівнів, укріплення <br/> лінійні ділянки авто-, залізничних доріг, нафтогазопроводів) <br/> • мостові споруди (підходи мостів та кесони опор) <br/> • різного виду підземні споруди та тунелі (технологія горизонтального-DTH) <br/> • глибокі котловани та багаторівневі паркінги для цивільних споруд. <br/><br/> <strong>Вироблені палі відповідають технічним умовам України ТУ У 24.2-455223116002:2025, спеціально розробленим для регулювання виробництва високоякісних та надійних паль.</strong>'},c={title:"У виробництві використовуються",headline:"ЗАМОК",tagline:"ТРУБА",motto:"ТРУБОШПУНТОВА ПАЛЯ"},u={title:"Сторінка в розробці",text:"Ми працюємо над цим розділом. Незабаром він буде доступний."},d={title:"ПАЛІ занурюються «замок у замок» і виходить:",firstTitle:"Портові Iнфраструктури",secondTitle:"Підпірних стін",thirdTitle:"Мостових Споруд",fourthTitle:"Тунелів",firstText:"Моли, причали, берегоукріплення.",secondText:"Віадуки, багаторівневі дорожні розв’язки, нафто- та газопроводів.",thirdText:"Підходи до мостів та кесони опор.",fourthText:"Будівництво порталів, підпірних конструкцій."},g={telTitle:"Телефон",emailTitle:"Пошта",telText:"+38 050 318 39 76",emailText:"info@pipepile.com.ua"},p={header:i,footer:a,hero:l,slogan:c,inProgress:u,features:d,contacts:g},h={gallery:"Gallery",manufacturing:"Manufacturing",documentation:"Documentation",contacts:"Contacts"},b={privacy:"© 2026 UPP Systems. All rights reserved.",accordionTitle:"Navigation"},m={title:"<strong>Ukraine Pipepiles</strong>",subtitle:'<strong> the first company in Ukraine </strong> that <u>exclusively</u> producing tubular sheet piles and beam sheet piles based on the patented MF-Pipe technology developed by SteelWall ISH GmbH (Germany). <br/> Tubular sheet piles and beam sheet piles have been widely used worldwide for many years in almost all infrastructure and hydraulic engineering projects. <br/> <br/> <span class="hero__lg">Now we produce them in Ukraine.</span><br/> <br/> The production uses <br/> <strong><u> certified steel pipes </u></strong> and I-beams from various manufacturers <br/> + <br/> <strong><u> unique patented sheet pile locks </strong></u> SteelWall ISH GMBH supplied to Ukraine exclusively by STEELWALL UKRAINE (www.steelwallukr.com ymatt24@yahoo.com) <br/> <br/> This allows the creation of <span class="hero__lg">highly reliable tubular sheet pile </span>systems for complex civil and hydraulic construction projects such as: <br/><br/> • port infrastructure (piers, berths, shoreline reinforcement)<br/> • retaining walls (viaducts, multi-level road interchanges, reinforcement <br/> linear sections of roads, railways, oil and gas pipelines) <br/> • bridge structures (bridge approaches and pier caissons) <br/> • various underground structures and tunnels (horizontal DTH technology) <br/> • deep excavations and multi-level parking structures for civil construction. <br/><br/> <strong>The produced piles comply with the technical specifications of Ukraine TU U 24.2-455223116002:2025, specially developed to regulate the production of high-quality and reliable piles.</strong>'},f={title:"The production uses",headline:"LOCK",tagline:"PIPE",motto:"TUBULAR SHEET PILE"},T={title:"Page in progress",text:"We are working on this section. It will be available soon."},y={title:"Piles are driven “lock into lock”, resulting in:",firstTitle:"Port Infrastructure",secondTitle:"Retaining Walls",thirdTitle:"Bridge Structures",fourthTitle:"Tunnels",firstText:"Breakwaters, piers, shoreline protection.",secondText:"Viaducts, multi-level road interchanges, oil and gas pipelines.",thirdText:"Bridge approaches and caisson supports.",fourthText:"Construction of portals, retaining structures."},v={telTitle:"Telephone",telText:"+38 050 318 39 76",emailTitle:"Email",emailText:"info@pipepile.com.ua"},w={header:h,footer:b,hero:m,slogan:f,inProgress:T,features:y,contacts:v},n={ua:p,en:w};function s(e,t){return t.split(".").reduce((r,o)=>r?.[o],e)??t}function x(e){document.querySelectorAll("[data-i18n]").forEach(t=>{const r=t.getAttribute("data-i18n");t.textContent=s(n[e],r)}),document.querySelectorAll("[data-i18n-html]").forEach(t=>{const r=t.getAttribute("data-i18n-html");t.innerHTML=s(n[e],r)})}function S(){return localStorage.getItem("lang")??"ua"}function P(e){localStorage.setItem("lang",e),document.documentElement.lang=e,x(e)}export{x as a,S as g,P as s};
